                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter quiz description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="duration"
